if.script:
def existing = ec.entity.find("trade.TradeApprovalRecord")
    .condition("transactionId", tx.transactionId)
    .condition("versionSnapshot", tx.versionNumber)
    .list()
if (existing.isEmpty()) {
    context.isFinalApproval = false
} else {
    for (prevAppr in existing) {
        if (prevAppr.approverUserId == approverUserId) {
            throw new org.moqui.service.ServiceException("Dual approval required: Current user has already approved this version.")
        }
    }
}

actions.script:
ec.artifactExecution.disableAuthz();
// Legacy amountAdjustment support
if (context.amountAdjustment != null) {
    if (context.amountAdjustment > 0) context.amountIncrease = context.amountAdjustment;
    else if (context.amountAdjustment < 0) context.amountDecrease = -context.amountAdjustment;
}
// Legacy newLcAmount support
if (context.newLcAmount != null) {
    def curLc = ec.entity.find("trade.importlc.ImportLetterOfCredit").condition("instrumentId", instrumentId).one();
    if (curLc != null) {
        def diff = context.newLcAmount - (curLc.effectiveAmount ?: 0);
        if (diff > 0) context.amountIncrease = diff;
        else if (diff < 0) context.amountDecrease = -diff;
    }
}
// Legacy narrative fields mapping
if (context.documentsActionEnumId) context.docsActionEnumId = context.documentsActionEnumId;
if (context.documentsDeltaText) context.docsDeltaText = context.documentsDeltaText;
if (context.additionalActionEnumId) context.conditionsActionEnumId = context.additionalActionEnumId;
if (context.additionalDeltaText) context.conditionsDeltaText = context.additionalDeltaText;
if (context.amendmentNarrative) {
    context.conditionsDeltaText = context.amendmentNarrative;
    context.conditionsActionEnumId = context.conditionsActionEnumId ?: 'REPLACE';
}
ec.logger.info("DEBUG: create#ExternalAmendment mapping: amountIncrease=${context.amountIncrease}, amountDecrease=${context.amountDecrease}, docsDeltaText=${context.docsDeltaText}")
